'use client'

import { useRef } from 'react'
import { useGSAP } from '@gsap/react'
import gsap from 'gsap'
import styles from './Donaciones.module.css'

export default function Donaciones() {
  const containerRef = useRef<HTMLDivElement>(null)

  useGSAP(() => {
    gsap.from('.donaciones-title', {
      opacity: 0,
      y: 30,
      duration: 0.8,
      ease: 'power3.out'
    })
    gsap.from('.donaciones-button', {
      opacity: 0,
      scale: 0.8,
      duration: 0.6,
      delay: 0.3,
      ease: 'back.out(1.7)'
    })
  }, { scope: containerRef })

  return (
    <section className={styles.donaciones} ref={containerRef}>
      <div className={styles.container}>
        <h2 className={`${styles.title} donaciones-title`}>¿Quieres hacer una donación o necesitas un bono de apoyo?</h2>
        <a href="#contacto" className={`${styles.button} donaciones-button`}>HAZ CLICK AQUÍ</a>
      </div>
    </section>
  )
}
